import React, { useState } from 'react';
import './App.css';

const MAX_WORDS = 100;

function App() {
  const [text, setText] = useState('');

  const handleChange = (e) => {
    const value = e.target.value;
    const wordCount = value.trim().split(/\s+/).filter(Boolean).length;
    if (wordCount <= MAX_WORDS || value.length < text.length) {
      setText(value);
    }
  };

  const wordCount = text.trim().split(/\s+/).filter(Boolean).length;

  const handleClick = (label) => {
    console.log(`${label} clicked:`, text);
    // add your logic here
  };

  const buttons = ['Professional', 'Friend', 'General', 'Professional', 'Friend', 'General'];

  return (
    <div className="page">
      <div className="rectangle">
        <textarea
          className="text-input"
          placeholder="Type your sentence here..."
          value={text}
          onChange={handleChange}
        />
        <div className="word-count">{wordCount}/{MAX_WORDS} words</div>
        <div className="button-grid">
          {buttons.map((label, i) => (
            <button key={i} className="btn" onClick={() => handleClick(label)}>
              {label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
